------------------------------------------------------------------------------
-- 9a. Governance, controls, and planning sample data
------------------------------------------------------------------------------



update scm_warehouse_areas
   set approved_for_high_value_flag = true,
       approved_for_sensitive_goods_flag = true
 where warehouse_id = (select warehouse_id from scm_warehouses where warehouse_code = 'WH-MUM-DC')
   and area_code in ('STO', 'PIC');

update scm_warehouse_areas
   set approved_for_high_value_flag = true,
       approved_for_sensitive_goods_flag = true,
       approved_for_restricted_goods_flag = true
 where warehouse_id = (select warehouse_id from scm_warehouses where warehouse_code = 'WH-BLR-FUL')
   and area_code in ('STO', 'PIC', 'QUA');

update scm_storage_locations
   set approved_for_high_value_flag = true
 where location_code in ('WH-MUM-DC-BULK', 'WH-MUM-DC-BIN');

update scm_storage_locations
   set approved_for_high_value_flag = true,
       approved_for_sensitive_goods_flag = true,
       approved_for_restricted_goods_flag = true
 where location_code in ('WH-BLR-FUL-BULK', 'WH-BLR-FUL-BIN', 'WH-BLR-FUL-QUAR');

update scm_item_warehouse_policies
   set count_tolerance_quantity = 1,
       count_tolerance_percent = 1.50,
       low_stock_alert_enabled_flag = true
 where item_id = (select item_id from scm_items where item_code = 'ITEM-004')
   and warehouse_id = (select warehouse_id from scm_warehouses where warehouse_code = 'WH-BLR-FUL');

update scm_item_warehouse_policies
   set count_tolerance_quantity = 2,
       count_tolerance_percent = 2.00,
       low_stock_alert_enabled_flag = true
 where item_id = (select item_id from scm_items where item_code = 'ITEM-016')
   and warehouse_id = (select warehouse_id from scm_warehouses where warehouse_code = 'WH-BLR-FUL');
















