------------------------------------------------------------------------------
-- 9e. Datamodel extension sample updates
------------------------------------------------------------------------------

update scm_items
   set handling_profile_code = case
                                   when item_code = 'ITEM-034' then 'CUSTOMER_CONTROLLED'
                                   when item_category_code = 'MED' then 'CONTROLLED_HANDLING'
                                   when item_category_code = 'CHEM' then 'HAZMAT_HANDLING'
                                   when item_category_code = 'FOOD' then 'FEFO_HANDLING'
                                   when fragile_flag then 'FRAGILE_HANDLING'
                                   else 'STANDARD_HANDLING'
                               end,
       storage_class_code = case
                                when item_code = 'ITEM-034' then 'SECURE_CONTROLLED'
                                when item_category_code = 'CHEM' then 'HAZMAT_SEPARATED'
                                when item_category_code = 'FOOD' then 'AMBIENT_FEFO'
                                when item_category_code = 'MED' then 'SECURE_CONTROLLED'
                                else 'GENERAL_PICK'
                            end,
       pack_uom_code = case
                           when item_code in ('ITEM-003', 'ITEM-009', 'ITEM-015', 'ITEM-027') then 'PLT'
                           when item_code in ('ITEM-010', 'ITEM-014', 'ITEM-028', 'ITEM-032') then 'BOX'
                           else null
                       end,
       pack_size_quantity = case
                                when item_code in ('ITEM-003', 'ITEM-009', 'ITEM-015', 'ITEM-027') then 48
                                when item_code in ('ITEM-010', 'ITEM-014', 'ITEM-028') then 6
                                when item_code = 'ITEM-032' then 20
                                else null
                            end,
       storage_handling_notes = case
                                    when item_code = 'ITEM-034' then 'Customer-owned diagnostic stock must remain in approved secure storage and release only under authorised clinic demand.'
                                    when item_category_code = 'MED' then 'Store in approved controlled-access locations and capture any review-driven disposition changes.'
                                    when item_category_code = 'CHEM' then 'Keep segregated from incompatible goods and follow hazardous handling guidance during putaway and issue.'
                                    when item_category_code = 'FOOD' then 'Rotate by FEFO and protect remaining shelf life before allocation or dispatch.'
                                    when fragile_flag then 'Protect from crush risk during putaway and picking; use stable tote or bin handling.'
                                    else 'Store in standard warehouse locations and replenish pick faces before scheduled release waves.'
                                end,
       stock_status_rule_code = case
                                    when item_code = 'ITEM-034' then 'CONTROLLED_RELEASE'
                                    when item_category_code in ('MED', 'CHEM') then 'QUARANTINE_ON_RECEIPT'
                                    when item_category_code = 'FOOD' then 'FEFO_CONTROLLED'
                                    else 'STANDARD_AVAILABLE'
                                end;

update scm_items
   set owner_customer_partner_id = (select business_partner_id from scm_business_partners where partner_number = 'CUS-004')
 where item_code = 'ITEM-034';

update scm_item_warehouse_policies p
   set preferred_storage_area_id = (
           select a.warehouse_area_id
             from scm_warehouse_areas a
            where a.warehouse_id = p.warehouse_id
              and a.area_code = (
                      select case
                                 when i.storage_class_code in ('AMBIENT_FEFO', 'HAZMAT_SEPARATED') then 'STO'
                                 else 'PIC'
                             end
                        from scm_items i
                       where i.item_id = p.item_id
                  )
       );

update scm_storage_locations
   set preferred_item_id = case location_code
                               when 'WH-MUM-DC-PICK' then (select item_id from scm_items where item_code = 'ITEM-025')
                               when 'WH-BLR-FUL-PICK' then (select item_id from scm_items where item_code = 'ITEM-031')
                               when 'WH-BLR-FUL-BIN' then (select item_id from scm_items where item_code = 'ITEM-034')
                               when 'WH-CHN-XD-PICK' then (select item_id from scm_items where item_code = 'ITEM-025')
                               else preferred_item_id
                           end,
       preferred_storage_class_code = case location_code
                                          when 'WH-MUM-DC-PICK' then 'GENERAL_PICK'
                                          when 'WH-BLR-FUL-PICK' then 'GENERAL_PICK'
                                          when 'WH-BLR-FUL-BIN' then 'SECURE_CONTROLLED'
                                          when 'WH-DEL-RET-BIN' then 'AMBIENT_FEFO'
                                          when 'WH-CHN-XD-PICK' then 'GENERAL_PICK'
                                          else preferred_storage_class_code
                                      end,
       allows_mixed_items = case location_code
                                when 'WH-MUM-DC-PICK' then true
                                when 'WH-BLR-FUL-PICK' then true
                                when 'WH-DEL-RET-PICK' then true
                                when 'WH-MUM-DC-BIN' then true
                                when 'WH-DEL-RET-BIN' then true
                                when 'WH-CHN-XD-PICK' then true
                                when 'WH-CHN-XD-BIN' then true
                                else allows_mixed_items
                            end,
       allows_mixed_lots = case location_code
                               when 'WH-MUM-DC-PICK' then true
                               when 'WH-CHN-XD-PICK' then true
                               else false
                           end
 where location_code in ('WH-MUM-DC-PICK', 'WH-MUM-DC-BIN', 'WH-BLR-FUL-PICK', 'WH-BLR-FUL-BIN', 'WH-DEL-RET-PICK', 'WH-DEL-RET-BIN', 'WH-CHN-XD-PICK', 'WH-CHN-XD-BIN');

update scm_inbound_receipt_lines l
   set final_putaway_location_id = (select storage_location_id from scm_storage_locations where location_code = 'WH-BLR-FUL-PICK'),
       putaway_override_reason_code = 'PICK_FACE_PRIORITY',
       putaway_override_notes = 'Directed reserve putaway was overridden to protect the immediate clinic pick face demand.',
       line_notes = 'Electrical stock was received in full and redirected from reserve bulk to the active pick face.'
 where l.inbound_receipt_id = (select inbound_receipt_id from scm_inbound_receipts where receipt_number = 'INB-0010')
   and l.line_number = 2;

update scm_inventory_transactions
   set to_location_id = (select storage_location_id from scm_storage_locations where location_code = 'WH-BLR-FUL-PICK'),
       reason_code = 'PICK_FACE_PRIORITY',
       reason_description = 'Electrical stock was redirected from reserve bulk to the clinic pick face after receipt.'
 where warehouse_id = (select warehouse_id from scm_warehouses where warehouse_code = 'WH-BLR-FUL')
   and transaction_type_code = 'PUTAWAY'
   and reference_document_type = 'INBOUND_RECEIPT'
   and reference_document_number = 'INB-0010'
   and item_id = (select item_id from scm_items where item_code = 'ITEM-031');

update scm_item_warehouse_policies p
   set safety_stock_quantity = nvl(minimum_stock_quantity, 0),
       replenishment_lead_time_days = 2
 where exists (
           select 1
             from scm_items i
            where i.item_id = p.item_id
              and i.item_category_code in ('ELEC', 'FMCG', 'SPARES')
       );

update scm_item_warehouse_policies p
   set safety_stock_quantity = nvl(minimum_stock_quantity, 0),
       replenishment_lead_time_days = 3
 where exists (
           select 1
             from scm_items i
            where i.item_id = p.item_id
              and i.item_category_code = 'FOOD'
       );

update scm_item_warehouse_policies p
   set safety_stock_quantity = nvl(minimum_stock_quantity, 0),
       replenishment_lead_time_days = 2
 where exists (
           select 1
             from scm_items i
            where i.item_id = p.item_id
              and i.item_category_code = 'MED'
       );

update scm_item_warehouse_policies p
   set safety_stock_quantity = nvl(minimum_stock_quantity, 0),
       replenishment_lead_time_days = 4
 where exists (
           select 1
             from scm_items i
            where i.item_id = p.item_id
              and i.item_category_code = 'CHEM'
       );

update scm_stock_transfers
   set expected_receipt_at = case transfer_number
                                 when 'TRF-0001' then to_timestamp_tz('2026-04-03 09:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0002' then to_timestamp_tz('2026-04-06 08:15:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0003' then to_timestamp_tz('2026-04-05 08:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0004' then to_timestamp_tz('2026-04-09 09:30:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0005' then to_timestamp_tz('2026-04-07 17:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0006' then to_timestamp_tz('2026-04-07 11:30:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0007' then to_timestamp_tz('2026-04-11 08:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0008' then to_timestamp_tz('2026-04-12 08:30:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                             end,
       confirmation_due_at = case transfer_number
                                 when 'TRF-0001' then to_timestamp_tz('2026-04-03 13:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0002' then to_timestamp_tz('2026-04-06 12:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0003' then to_timestamp_tz('2026-04-05 12:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0004' then to_timestamp_tz('2026-04-09 12:30:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0005' then to_timestamp_tz('2026-04-07 20:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0006' then to_timestamp_tz('2026-04-07 15:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0007' then to_timestamp_tz('2026-04-11 12:00:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                                 when 'TRF-0008' then to_timestamp_tz('2026-04-12 12:30:00 +05:30','YYYY-MM-DD HH24:MI:SS TZH:TZM')
                             end
 where transfer_number in ('TRF-0001', 'TRF-0002', 'TRF-0003', 'TRF-0004', 'TRF-0005', 'TRF-0006', 'TRF-0007', 'TRF-0008');

update scm_stock_transfer_lines l
   set (unit_cost_amount, currency_code) = (
           select case i.item_code
                      when 'ITEM-001' then 1250
                      when 'ITEM-003' then 780
                      when 'ITEM-004' then 68500
                      when 'ITEM-005' then 430
                      when 'ITEM-011' then 560
                      when 'ITEM-015' then 910
                      when 'ITEM-019' then 1450
                      when 'ITEM-020' then 1320
                      when 'ITEM-021' then 980
                      when 'ITEM-024' then 1100
                      when 'ITEM-025' then 7200
                      when 'ITEM-027' then 1850
                      when 'ITEM-031' then 8400
                      when 'ITEM-034' then 92500
                      else 1000
                  end,
                  'INR'
             from scm_items i
            where i.item_id = l.item_id
       );

update scm_stock_transfer_lines
   set transfer_discrepancy_reason_code = 'SHORT_RECEIPT',
       transfer_discrepancy_notes = 'Four units were still missing when the Delhi receiving team confirmed the first transfer receipt.'
 where stock_transfer_id = (select stock_transfer_id from scm_stock_transfers where transfer_number = 'TRF-0006')
   and line_number = 1;

update scm_stock_adjustment_lines l
   set (unit_cost_amount, currency_code) = (
           select case i.item_code
                      when 'ITEM-001' then 1250
                      when 'ITEM-004' then 68500
                      when 'ITEM-007' then 980
                      when 'ITEM-010' then 12250
                      when 'ITEM-014' then 1600
                      when 'ITEM-016' then 21800
                      when 'ITEM-021' then 980
                      when 'ITEM-028' then 24500
                      when 'ITEM-034' then 92500
                      else 1000
                  end,
                  'INR'
             from scm_items i
            where i.item_id = l.item_id
       );

update scm_stock_count_lines l
   set (unit_cost_amount, currency_code) = (
           select case i.item_code
                      when 'ITEM-001' then 1250
                      when 'ITEM-003' then 780
                      when 'ITEM-004' then 68500
                      when 'ITEM-010' then 12250
                      when 'ITEM-016' then 21800
                      when 'ITEM-019' then 1450
                      when 'ITEM-020' then 1320
                      when 'ITEM-021' then 980
                      when 'ITEM-025' then 7200
                      when 'ITEM-027' then 1850
                      when 'ITEM-028' then 24500
                      when 'ITEM-031' then 8400
                      else 1000
                  end,
                  'INR'
             from scm_items i
            where i.item_id = l.item_id
       );

commit;

